// Claudeの応答からJSONを取り出し、relevantかつnameがある時だけ次へ
const t = ($json.content && $json.content[0] && $json.content[0].text) || '';
let u;
try { u = JSON.parse(String(t).replace(/```json|```/g, '').trim()); } catch (e) { return []; }
if (!u || !u.relevant || !u.name) return [];
delete u.relevant;
return [{ json: { update: u } }];
